print(f"{(a := float(input('Insira o valor de a: '))) and ''}{(b := float(input('Insira o valor de b: '))) and ''}{(c := float(input('Insira o valor de c: '))) and ''}{(delta := b ** 2 - 4 * a * c) and ''}{('A equação não possui raízes reais.' if delta < 0 else (f'A equação possui apenas uma raiz real: {-b / (2 * a):.2f}.' if delta == 0 else f'A equação possui duas raízes reais: {(-b + delta ** 0.5) / (2 * a):.2f} e {(-b - delta ** 0.5) / (2 * a):.2f}.'))}")
